def compute_feature(ctx):
    helpers = ctx["helpers"]
    h2v_a = ctx["stats_a"]["header_to_value"]
    h2v_b = ctx["stats_b"]["header_to_value"]
    pairs_a = set()
    pairs_b = set()
    for k in h2v_a.keys():
        v = h2v_a.get(k, "")
        pairs_a.add(str(k) + "=" + str(v))
    for k in h2v_b.keys():
        v = h2v_b.get(k, "")
        pairs_b.add(str(k) + "=" + str(v))
    if not pairs_a and not pairs_b:
        return 0.0
    return helpers["set_jaccard"](pairs_a, pairs_b)

def compute_feature(ctx):
    a = ctx["stats_a"]["token_set"]
    b = ctx["stats_b"]["token_set"]
    if not a or not b:
        return 0.0
    inter = len(a.intersection(b))
    denom = float(min(len(a), len(b)))
    if denom <= 0.0:
        return 0.0
    val = inter / denom
    if val < 0.0:
        return 0.0
    if val > 1.0:
        return 1.0
    return float(val)

