def compute_feature(ctx):
    a = int(ctx["stats_a"]["nonempty_count"])
    b = int(ctx["stats_b"]["nonempty_count"])
    denom = float(max(a + b, 1))
    diff = abs(a - b) / denom
    val = 1.0 - float(diff)
    if val < 0.0:
        return 0.0
    if val > 1.0:
        return 1.0
    return float(val)

def compute_feature(ctx):
    cos = ctx["helpers"]["cosine_similarity"](ctx["emb_a"], ctx["emb_b"])
    val = (float(cos) + 1.0) / 2.0
    return ctx["helpers"]["clip01"](val)
